/**
 * 极简 Excel (.xlsx) 生成器
 * 基于 OpenXML 标准实现，不依赖任何外部库
 * 支持：中文内容、多行数据、列宽设置、首行冻结
 */

(function(global) {
  'use strict';

  // ============================================================
  // ZIP 工具（极简实现，无压缩，仅打包）
  // ============================================================
  function strToBytes(str) {
    const encoder = new TextEncoder();
    return encoder.encode(str);
  }

  function uint32LE(n) {
    return [n & 0xFF, (n >> 8) & 0xFF, (n >> 16) & 0xFF, (n >> 24) & 0xFF];
  }
  function uint16LE(n) {
    return [n & 0xFF, (n >> 8) & 0xFF];
  }

  // CRC32 表
  const crcTable = (() => {
    const t = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      t[i] = c;
    }
    return t;
  })();

  function crc32(data) {
    let crc = 0xFFFFFFFF;
    for (let i = 0; i < data.length; i++) crc = crcTable[(crc ^ data[i]) & 0xFF] ^ (crc >>> 8);
    return (crc ^ 0xFFFFFFFF) >>> 0;
  }

  function buildZip(files) {
    // files: [{name, data: Uint8Array}]
    const localHeaders = [];
    const centralHeaders = [];
    let offset = 0;

    files.forEach(file => {
      const nameBytes = strToBytes(file.name);
      const data = file.data instanceof Uint8Array ? file.data : strToBytes(file.data);
      const crc = crc32(data);
      const size = data.length;

      // Local file header
      const local = new Uint8Array(30 + nameBytes.length + size);
      let p = 0;
      // Signature
      local[p++]=0x50;local[p++]=0x4B;local[p++]=0x03;local[p++]=0x04;
      // Version
      local[p++]=0x14;local[p++]=0x00;
      // Flags
      local[p++]=0x00;local[p++]=0x00;
      // Compression (STORE)
      local[p++]=0x00;local[p++]=0x00;
      // Mod time/date (dummy)
      local[p++]=0x00;local[p++]=0x00;local[p++]=0x00;local[p++]=0x00;
      // CRC32
      uint32LE(crc).forEach(b => local[p++]=b);
      // Compressed size
      uint32LE(size).forEach(b => local[p++]=b);
      // Uncompressed size
      uint32LE(size).forEach(b => local[p++]=b);
      // File name length
      uint16LE(nameBytes.length).forEach(b => local[p++]=b);
      // Extra field length
      local[p++]=0x00;local[p++]=0x00;
      // File name
      nameBytes.forEach(b => local[p++]=b);
      // Data
      data.forEach(b => local[p++]=b);

      localHeaders.push({ local, offset, nameBytes, crc, size });
      offset += local.length;
    });

    // Central directory
    const centralParts = [];
    localHeaders.forEach(h => {
      const cd = new Uint8Array(46 + h.nameBytes.length);
      let p = 0;
      cd[p++]=0x50;cd[p++]=0x4B;cd[p++]=0x01;cd[p++]=0x02;
      cd[p++]=0x14;cd[p++]=0x00; // version made by
      cd[p++]=0x14;cd[p++]=0x00; // version needed
      cd[p++]=0x00;cd[p++]=0x00; // flags
      cd[p++]=0x00;cd[p++]=0x00; // compression
      cd[p++]=0x00;cd[p++]=0x00; // mod time
      cd[p++]=0x00;cd[p++]=0x00; // mod date
      uint32LE(h.crc).forEach(b => cd[p++]=b);
      uint32LE(h.size).forEach(b => cd[p++]=b);
      uint32LE(h.size).forEach(b => cd[p++]=b);
      uint16LE(h.nameBytes.length).forEach(b => cd[p++]=b);
      cd[p++]=0x00;cd[p++]=0x00; // extra
      cd[p++]=0x00;cd[p++]=0x00; // comment
      cd[p++]=0x00;cd[p++]=0x00; // disk start
      cd[p++]=0x00;cd[p++]=0x00; // internal attr
      cd[p++]=0x00;cd[p++]=0x00;cd[p++]=0x00;cd[p++]=0x00; // external attr
      uint32LE(h.offset).forEach(b => cd[p++]=b);
      h.nameBytes.forEach(b => cd[p++]=b);
      centralParts.push(cd);
    });

    const cdSize = centralParts.reduce((s, c) => s + c.length, 0);
    const cdOffset = offset;

    // End of central directory
    const eocd = new Uint8Array(22);
    let p = 0;
    eocd[p++]=0x50;eocd[p++]=0x4B;eocd[p++]=0x05;eocd[p++]=0x06;
    eocd[p++]=0x00;eocd[p++]=0x00; // disk num
    eocd[p++]=0x00;eocd[p++]=0x00; // disk with cd
    uint16LE(files.length).forEach(b => eocd[p++]=b);
    uint16LE(files.length).forEach(b => eocd[p++]=b);
    uint32LE(cdSize).forEach(b => eocd[p++]=b);
    uint32LE(cdOffset).forEach(b => eocd[p++]=b);
    eocd[p++]=0x00;eocd[p++]=0x00; // comment length

    // Merge all
    const totalSize = localHeaders.reduce((s, h) => s + h.local.length, 0) + cdSize + 22;
    const result = new Uint8Array(totalSize);
    let pos = 0;
    localHeaders.forEach(h => { result.set(h.local, pos); pos += h.local.length; });
    centralParts.forEach(cd => { result.set(cd, pos); pos += cd.length; });
    result.set(eocd, pos);
    return result;
  }

  // ============================================================
  // XML 转义
  // ============================================================
  function xmlEsc(s) {
    return String(s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  }

  // ============================================================
  // XLSX 构建
  // ============================================================
  function buildXlsx(aoa, sheetName, colWidths) {
    sheetName = sheetName || 'Sheet1';

    // 共享字符串表
    const sharedStrings = [];
    const ssMap = {};
    function getSSI(s) {
      const key = String(s);
      if (ssMap[key] === undefined) {
        ssMap[key] = sharedStrings.length;
        sharedStrings.push(key);
      }
      return ssMap[key];
    }

    // 列名映射 (0-based index -> letter)
    function colLetter(n) {
      let s = '';
      n++;
      while (n > 0) {
        const r = (n - 1) % 26;
        s = String.fromCharCode(65 + r) + s;
        n = Math.floor((n - 1) / 26);
      }
      return s;
    }

    // 构建 sheet XML
    let sheetXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n';
    sheetXml += '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">';

    // 冻结首行
    sheetXml += '<sheetViews><sheetView tabSelected="1" workbookViewId="0">';
    sheetXml += '<pane ySplit="1" topLeftCell="A2" activePane="bottomLeft" state="frozen"/>';
    sheetXml += '</sheetView></sheetViews>';

    // 列宽
    if (colWidths && colWidths.length > 0) {
      sheetXml += '<cols>';
      colWidths.forEach((w, i) => {
        sheetXml += `<col min="${i+1}" max="${i+1}" width="${w}" customWidth="1"/>`;
      });
      sheetXml += '</cols>';
    }

    sheetXml += '<sheetData>';
    aoa.forEach((row, ri) => {
      sheetXml += `<row r="${ri+1}">`;
      row.forEach((cell, ci) => {
        const addr = `${colLetter(ci)}${ri+1}`;
        const val = cell == null ? '' : String(cell);
        if (val === '') {
          sheetXml += `<c r="${addr}"/>`;
        } else {
          const si = getSSI(val);
          sheetXml += `<c r="${addr}" t="s"><v>${si}</v></c>`;
        }
      });
      sheetXml += '</row>';
    });
    sheetXml += '</sheetData></worksheet>';

    // 共享字符串 XML
    const ssXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="${sharedStrings.length}" uniqueCount="${sharedStrings.length}">
${sharedStrings.map(s => `<si><t xml:space="preserve">${xmlEsc(s)}</t></si>`).join('\n')}
</sst>`;

    // workbook.xml
    const wbXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"
  xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
  <sheets><sheet name="${xmlEsc(sheetName)}" sheetId="1" r:id="rId1"/></sheets>
</workbook>`;

    // workbook relationships
    const wbRels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>
  <Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" Target="sharedStrings.xml"/>
</Relationships>`;

    // package relationships
    const pkgRels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>
</Relationships>`;

    // content types
    const contentTypes = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>
  <Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>
  <Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>
</Types>`;

    // Build zip
    const zip = buildZip([
      { name: '[Content_Types].xml', data: contentTypes },
      { name: '_rels/.rels', data: pkgRels },
      { name: 'xl/workbook.xml', data: wbXml },
      { name: 'xl/_rels/workbook.xml.rels', data: wbRels },
      { name: 'xl/worksheets/sheet1.xml', data: sheetXml },
      { name: 'xl/sharedStrings.xml', data: ssXml },
    ]);

    return zip;
  }

  // ============================================================
  // 下载入口
  // ============================================================
  function writeFile(aoa, filename, options) {
    options = options || {};
    const colWidths = options.colWidths || [];
    const sheetName = options.sheetName || 'Sheet1';

    const data = buildXlsx(aoa, sheetName, colWidths);
    const blob = new Blob([data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  }

  // 暴露到全局（兼容 XLSX.writeFile / XLSX.utils.aoa_to_sheet 接口）
  global.XLSX = {
    utils: {
      book_new: () => ({ sheets: {}, SheetNames: [] }),
      book_append_sheet: (wb, ws, name) => { wb.sheets[name] = ws; wb.SheetNames.push(name); },
      aoa_to_sheet: (aoa) => aoa  // 直接传 aoa
    },
    writeFile: (wb, filename) => {
      const sheetName = wb.SheetNames[0];
      const aoa = wb.sheets[sheetName];
      writeFile(aoa, filename, {
        sheetName,
        colWidths: [20,25,25,15,12,15,20,15,10,12,15,25,15,15]
      });
    }
  };

})(typeof self !== 'undefined' ? self : this);
